package com.example.readerapp.ui.reader

import android.os.Bundle
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import androidx.compose.animation.*
import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.Canvas
import androidx.compose.foundation.interaction.MutableInteractionSource
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.ArrowBack
import androidx.compose.material.icons.filled.*
import androidx.compose.material.icons.outlined.BookmarkBorder
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.geometry.Offset
import androidx.compose.ui.platform.ComposeView
import androidx.compose.ui.unit.dp
import androidx.compose.animation.core.animateFloatAsState
import androidx.compose.foundation.interaction.collectIsDraggedAsState
import androidx.compose.foundation.interaction.collectIsPressedAsState
import androidx.compose.foundation.isSystemInDarkTheme
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.graphicsLayer
import androidx.compose.ui.unit.sp
import androidx.lifecycle.*
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.fragment.app.FragmentContainerView
import com.example.readerapp.ReaderApplication
import com.example.readerapp.data.local.ReaderPreferences
import com.example.readerapp.ui.components.ReaderSettingsContent
import com.example.readerapp.ui.theme.ReaderAppTheme
import kotlinx.coroutines.flow.filterNotNull
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.launch
import kotlin.math.abs
import org.readium.r2.navigator.epub.EpubNavigatorFactory
import org.readium.r2.navigator.epub.EpubNavigatorFragment
import org.readium.r2.navigator.input.InputListener
import org.readium.r2.navigator.input.TapEvent

import org.readium.r2.shared.publication.Link
import org.readium.r2.shared.publication.Publication

class ReaderActivity : AppCompatActivity() {

    companion object {
        const val EXTRA_BOOK_ID = "bookId"
        private const val NAVIGATOR_TAG = "epub_navigator"
    }

    private val viewModel: ReaderViewModel by viewModels {
        val bookId = intent.getStringExtra(EXTRA_BOOK_ID) ?: ""
        val app = application as ReaderApplication
        ReaderViewModel.Factory(
            bookId = bookId,
            repository = app.bookRepository,
            readerPreferences = ReaderPreferences(applicationContext)
        )
    }

    private var navigator: EpubNavigatorFragment? = null
    private var navigatorContainer: FragmentContainerView? = null
    private val navigatorFlow = MutableStateFlow<EpubNavigatorFragment?>(null)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(com.example.readerapp.R.layout.activity_reader)

        val composeView = findViewById<ComposeView>(com.example.readerapp.R.id.compose_overlay)
        navigatorContainer = findViewById(com.example.readerapp.R.id.navigator_container)

        androidx.core.view.ViewCompat.setOnApplyWindowInsetsListener(navigatorContainer!!) { _, insets ->
            androidx.core.view.WindowInsetsCompat.CONSUMED
        }

        val rootLayout = findViewById<android.widget.FrameLayout>(com.example.readerapp.R.id.reader_root)

        // Open the book
        if (savedInstanceState == null) {
            viewModel.openBook()
        }

        // Observe publication and set up navigator
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.publication.filterNotNull().collect { publication ->
                    if (navigator == null) {
                        setupNavigator(publication)
                    }
                }
            }
        }

        // Observe settings flow to dynamically update background and navigator margins
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.settingsFlow.collect { settings ->
                    val color = when (settings.readerThemePreset) {
                        "Light" -> android.graphics.Color.parseColor("#FFFFFF")
                        "Warm" -> android.graphics.Color.parseColor("#FAF4E8")
                        "Dark" -> android.graphics.Color.parseColor("#000000")
                        else -> {
                            val isSystemDark = (resources.configuration.uiMode and android.content.res.Configuration.UI_MODE_NIGHT_MASK) == android.content.res.Configuration.UI_MODE_NIGHT_YES
                            if (isSystemDark) android.graphics.Color.parseColor("#000000") else android.graphics.Color.parseColor("#FFFFFF")
                        }
                    }
                    // Paint at the window level so the ENTIRE screen is one uniform
                    // color — including any margin gaps around the navigator.
                    window.decorView.setBackgroundColor(color)
                    rootLayout?.setBackgroundColor(color)

                    // In scroll mode: full screen (no margins).
                    // In pagination mode: 48dp top/bottom margin on the navigator.
                    val marginPx = if (settings.scroll) {
                        0
                    } else {
                        (48 * resources.displayMetrics.density).toInt()
                    }
                    navigatorContainer?.let { container ->
                        val lp = container.layoutParams as android.widget.FrameLayout.LayoutParams
                        lp.topMargin = marginPx
                        lp.bottomMargin = marginPx
                        container.layoutParams = lp
                    }
                }
            }
        }

        // Observe preferences and submit to navigator reactively when either navigator or preferences change
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                combine(navigatorFlow.filterNotNull(), viewModel.epubPreferences) { nav, prefs ->
                    nav to prefs
                }.collect { (nav, prefs) ->
                    nav.submitPreferences(prefs)
                }
            }
        }

        // Observe current locator for position saving and UI updates reactively from active navigator
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                navigatorFlow.collectLatest { nav ->
                    nav?.currentLocator?.collect { locator ->
                        viewModel.onLocatorChanged(locator)
                        viewModel.savePosition(locator)
                    }
                }
            }
        }

        // Observe brightness
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.brightness.collect { brightness ->
                    val layoutParams = window.attributes
                    layoutParams.screenBrightness = brightness
                    window.attributes = layoutParams
                }
            }
        }


        // Set up Compose overlay
        composeView.setContent {
            // The overlay theme is driven by the reader's own theme setting so that
            // icon/text colours always contrast with the reader background.
            val settingsState = viewModel.settingsFlow.collectAsState(
                initial = com.example.readerapp.data.local.ReaderSettings()
            )
            val overlaySettings = settingsState.value
            val isSystemDark = isSystemInDarkTheme()
            val overlayDarkTheme = when (overlaySettings.readerThemePreset) {
                "Dark" -> true
                "Light", "Warm" -> false
                else -> when (overlaySettings.themeMode) {
                    "Dark" -> true
                    "Light" -> false
                    else -> isSystemDark
                }
            }
            ReaderAppTheme(darkTheme = overlayDarkTheme, colorPalette = overlaySettings.colorPalette) {
                ReaderOverlay(
                    viewModel = viewModel,
                    onBack = { finish() },
                    onNavigateToChapter = { link ->
                        lifecycleScope.launch {
                            navigator?.go(link)
                        }
                    },
                    onSeekToProgression = { progression ->
                        val locator = viewModel.locatorForProgression(progression)
                        if (locator != null) {
                            lifecycleScope.launch {
                                navigator?.go(locator)
                            }
                        }
                    }
                )
            }
        }
    }

    private fun setupNavigator(publication: Publication) {
        if (supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) != null) {
            navigator = supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) as? EpubNavigatorFragment
            navigator?.let {
                setupNavigatorListener(it)
                navigatorFlow.value = it
            }
            return
        }

        val navigatorFactory = EpubNavigatorFactory(
            publication = publication
        )

        val initialLocator = viewModel.initialLocator
        val initialPreferences = viewModel.epubPreferences.value

        supportFragmentManager.fragmentFactory = navigatorFactory.createFragmentFactory(
            initialLocator = initialLocator,
            initialPreferences = initialPreferences
        )

        supportFragmentManager.beginTransaction()
            .replace(
                com.example.readerapp.R.id.navigator_container,
                EpubNavigatorFragment::class.java,
                Bundle(),
                NAVIGATOR_TAG
            )
            .commit()

        supportFragmentManager.executePendingTransactions()
        navigator = supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) as? EpubNavigatorFragment
        navigator?.let {
            setupNavigatorListener(it)
            navigatorFlow.value = it
        }
    }

    private fun setupNavigatorListener(nav: EpubNavigatorFragment) {
        // 1) DirectionalNavigationAdapter — registered FIRST so it gets priority.
        //    It handles both swipe gestures and edge taps out of the box:
        //      • Swipe left / right edge tap  → goForward()  (next page or chapter)
        //      • Swipe right / left edge tap  → goBackward() (prev page or chapter)
        (nav as? org.readium.r2.navigator.OverflowableNavigator)?.let { overflowableNav ->
            nav.addInputListener(
                org.readium.r2.navigator.util.DirectionalNavigationAdapter(
                    navigator = overflowableNav,
                    animatedTransition = true
                )
            )
        }

        // 2) Tap listener — registered SECOND so edge taps consumed above never reach here.
        //    Only un-consumed taps (centre area) toggle the controls overlay.
        nav.addInputListener(object : InputListener {
            override fun onTap(event: TapEvent): Boolean {
                viewModel.toggleControls()
                return true
            }
        })
    }

    override fun onPause() {
        super.onPause()
        // Save position when leaving
        navigator?.currentLocator?.value?.let { locator ->
            lifecycleScope.launch {
                viewModel.savePosition(locator)
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        viewModel.closeBook()
    }


}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ReaderOverlay(
    viewModel: ReaderViewModel,
    onBack: () -> Unit,
    onNavigateToChapter: (Link) -> Unit,
    onSeekToProgression: (Double) -> Unit
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val isBookmarked by viewModel.isBookmarked.collectAsStateWithLifecycle()
    val settings by viewModel.settingsFlow.collectAsStateWithLifecycle(
        initialValue = com.example.readerapp.data.local.ReaderSettings()
    )

    var isSeeking by remember { mutableStateOf(false) }
    var sliderPosition by remember { mutableFloatStateOf(uiState.progression.toFloat()) }
    var pendingSeek by remember { mutableStateOf<Double?>(null) }

    val interactionSource = remember { MutableInteractionSource() }
    val isPressed by interactionSource.collectIsPressedAsState()
    val isDragged by interactionSource.collectIsDraggedAsState()
    val isInteracting = isPressed || isDragged || isSeeking

    LaunchedEffect(uiState.progression) {
        val target = pendingSeek
        if (!isSeeking) {
            if (target == null || abs(uiState.progression - target) < 0.02) {
                pendingSeek = null
                sliderPosition = uiState.progression.toFloat().coerceIn(0f, 1f)
            }
        }
    }

    val readerBgColor = when (settings.readerThemePreset) {
        "Light" -> Color(0xFFFFFFFF)
        "Warm" -> Color(0xFFFAF4E8)
        "Dark" -> Color(0xFF000000)
        else -> if (isSystemInDarkTheme()) Color(0xFF000000) else Color(0xFFFFFFFF)
    }

    // Settings bottom sheet
    val settingsSheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    // TOC bottom sheet  
    val tocSheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)

    Box(modifier = Modifier.fillMaxSize()) {

        // Loading state
        if (uiState.isLoading) {
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.Center
            ) {
                CircularProgressIndicator()
            }
        }

        // Error state
        uiState.error?.let { error ->
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = error,
                    color = MaterialTheme.colorScheme.error,
                    style = MaterialTheme.typography.bodyLarge
                )
            }
        }

        // Animated controls overlay
        AnimatedVisibility(
            visible = uiState.showControls,
            enter = fadeIn(),
            exit = fadeOut()
        ) {
            Box(modifier = Modifier.fillMaxSize()) {
                // Top bar with gradient background (readerBg → transparent, top to bottom)
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.TopCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(readerBgColor, Color.Transparent)
                            )
                        )
                ) {
                    TopAppBar(
                        title = { },
                        navigationIcon = {
                            IconButton(onClick = onBack) {
                                Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                            }
                        },
                        actions = {
                            IconButton(onClick = { /* TODO: Search */ }) {
                                Icon(Icons.Default.Search, contentDescription = "Search")
                            }
                            IconButton(onClick = { viewModel.showToc() }) {
                                Icon(Icons.Filled.List, contentDescription = "Table of Contents")
                            }
                            IconButton(onClick = { viewModel.showSettings() }) {
                                Icon(Icons.Filled.Settings, contentDescription = "Settings")
                            }

                            var showMoreMenu by remember { mutableStateOf(false) }
                            Box {
                                IconButton(onClick = { showMoreMenu = true }) {
                                    Icon(Icons.Default.MoreVert, contentDescription = "More")
                                }
                                DropdownMenu(
                                    expanded = showMoreMenu,
                                    onDismissRequest = { showMoreMenu = false }
                                ) {
                                    DropdownMenuItem(
                                        text = { Text(if (isBookmarked) "Remove Bookmark" else "Add Bookmark") },
                                        onClick = {
                                            viewModel.toggleBookmark()
                                            showMoreMenu = false
                                        },
                                        leadingIcon = {
                                            Icon(
                                                if (isBookmarked) Icons.Filled.Bookmark else Icons.Outlined.BookmarkBorder,
                                                contentDescription = null
                                            )
                                        }
                                    )
                                }
                            }
                        },
                        colors = TopAppBarDefaults.topAppBarColors(
                            containerColor = Color.Transparent,
                            navigationIconContentColor = MaterialTheme.colorScheme.onSurface,
                            actionIconContentColor = MaterialTheme.colorScheme.onSurface
                        )
                    )
                }

                // Bottom bar
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.BottomCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(Color.Transparent, readerBgColor),
                                startY = 0f
                            )
                        )
                        .padding(horizontal = 24.dp)
                        .padding(top = 64.dp, bottom = 4.dp)
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        // Progress slider — thin track always visible; thumb + active track
                        // only appear when the user is interacting.
                        val sliderAlpha by animateFloatAsState(
                            targetValue = if (isInteracting) 1f else 0f,
                            label = "sliderInteractAlpha"
                        )
                        val onSurface = MaterialTheme.colorScheme.onSurface
                        val primary = MaterialTheme.colorScheme.primary

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(20.dp), // consistent hit area
                            contentAlignment = Alignment.Center
                        ) {
                            // Passive thin track (always visible, no thumb border artifact)
                            if (!isInteracting) {
                                androidx.compose.foundation.Canvas(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(2.dp)
                                ) {
                                    val trackY = size.height / 2
                                    // inactive portion
                                    drawLine(
                                        color = onSurface.copy(alpha = 0.24f),
                                        start = androidx.compose.ui.geometry.Offset(0f, trackY),
                                        end = androidx.compose.ui.geometry.Offset(size.width, trackY),
                                        strokeWidth = 2.dp.toPx(),
                                        cap = androidx.compose.ui.graphics.StrokeCap.Round
                                    )
                                    // active portion
                                    drawLine(
                                        color = onSurface.copy(alpha = 0.70f),
                                        start = androidx.compose.ui.geometry.Offset(0f, trackY),
                                        end = androidx.compose.ui.geometry.Offset(
                                            size.width * sliderPosition, trackY
                                        ),
                                        strokeWidth = 2.dp.toPx(),
                                        cap = androidx.compose.ui.graphics.StrokeCap.Round
                                    )
                                }
                            }

                            // Full Material 3 slider (visible only when interacting)
                            Slider(
                                value = sliderPosition,
                                onValueChange = {
                                    isSeeking = true
                                    sliderPosition = it.coerceIn(0f, 1f)
                                },
                                onValueChangeFinished = {
                                    isSeeking = false
                                    pendingSeek = sliderPosition.toDouble()
                                    onSeekToProgression(sliderPosition.toDouble())
                                },
                                interactionSource = interactionSource,
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .graphicsLayer { alpha = sliderAlpha }
                            )
                        }

                        Spacer(modifier = Modifier.height(4.dp))

                        // Page info text
                        val pageText = if (uiState.currentPage != null && uiState.totalPages != null) {
                            "${uiState.currentPage} of ${uiState.totalPages}"
                        } else {
                            "${(uiState.progression * 100).toInt()}%"
                        }

                        Text(
                            text = pageText,
                            style = MaterialTheme.typography.bodySmall.copy(
                                fontWeight = androidx.compose.ui.text.font.FontWeight.Medium,
                                letterSpacing = 0.5.sp
                            ),
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }
        }

        // TOC Bottom Sheet
        if (uiState.showToc) {
            ModalBottomSheet(
                onDismissRequest = { viewModel.hideToc() },
                sheetState = tocSheetState
            ) {
                Text(
                    text = "Table of Contents",
                    style = MaterialTheme.typography.titleLarge,
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)
                )
                HorizontalDivider()
                LazyColumn(
                    modifier = Modifier.fillMaxWidth(),
                    contentPadding = PaddingValues(vertical = 8.dp)
                ) {
                    items(viewModel.tableOfContents) { link ->
                        ListItem(
                            headlineContent = {
                                Text(link.title ?: link.href.toString())
                            },
                            modifier = Modifier.clickable {
                                onNavigateToChapter(link)
                                viewModel.hideToc()
                                viewModel.toggleControls()
                            }
                        )
                    }
                }
            }
        }

        // Settings Bottom Sheet — wrapped in its own theme that honours the UI
        // themeMode/colorPalette setting, independent of the reader theme.
        if (uiState.showSettings) {
            val uiDarkTheme = when (settings.themeMode) {
                "Dark" -> true
                "Light" -> false
                else -> isSystemInDarkTheme()
            }
            ReaderAppTheme(darkTheme = uiDarkTheme, colorPalette = settings.colorPalette) {
                ModalBottomSheet(
                    onDismissRequest = { viewModel.hideSettings() },
                    sheetState = settingsSheetState
                ) {
                    ReaderSettingsContent(
                        settings = settings,
                        onSettingsChange = { newSettings ->
                            viewModel.updateSettings(newSettings)
                        }
                    )
                }
            }
        }
    }
}

package com.example.readerapp.ui.reader

import android.os.Bundle
