        // Observe brightness
        lifecycleScope.launch {
            repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.brightness.collect { brightness ->
                    val layoutParams = window.attributes
                    layoutParams.screenBrightness = brightness
                    window.attributes = layoutParams
                }
            }
        }


        // Set up Compose overlay
        composeView.setContent {
            // The overlay theme is driven by the reader's own theme setting so that
            // icon/text colours always contrast with the reader background.
            val settingsState = viewModel.settingsFlow.collectAsState(
                initial = com.example.readerapp.data.local.ReaderSettings()
            )
            val overlaySettings = settingsState.value
            val isSystemDark = isSystemInDarkTheme()
            val overlayDarkTheme = when (overlaySettings.readerThemePreset) {
                "Dark" -> true
                "Light", "Warm" -> false
                else -> when (overlaySettings.themeMode) {
                    "Dark" -> true
                    "Light" -> false
                    else -> isSystemDark
                }
            }
            ReaderAppTheme(darkTheme = overlayDarkTheme, colorPalette = overlaySettings.colorPalette) {
                ReaderOverlay(
                    viewModel = viewModel,
                    onBack = { finish() },
                    onNavigateToChapter = { link ->
                        lifecycleScope.launch {
                            navigator?.go(link)
                        }
                    },
                    onSeekToProgression = { progression ->
                        val locator = viewModel.locatorForProgression(progression)
                        if (locator != null) {
                            lifecycleScope.launch {
                                navigator?.go(locator)
                            }
                        }
                    }
                )
            }
        }
    }

    private fun setupNavigator(publication: Publication) {
        if (supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) != null) {
            navigator = supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) as? EpubNavigatorFragment
            navigator?.let {
                setupNavigatorListener(it)
                navigatorFlow.value = it
            }
            return
        }

        val navigatorFactory = EpubNavigatorFactory(
            publication = publication
        )

        val initialLocator = viewModel.initialLocator
        val initialPreferences = viewModel.epubPreferences.value

        supportFragmentManager.fragmentFactory = navigatorFactory.createFragmentFactory(
            initialLocator = initialLocator,
            initialPreferences = initialPreferences
        )

        supportFragmentManager.beginTransaction()
            .replace(
                com.example.readerapp.R.id.navigator_container,
                EpubNavigatorFragment::class.java,
                Bundle(),
                NAVIGATOR_TAG
            )
            .commit()

        supportFragmentManager.executePendingTransactions()
        navigator = supportFragmentManager.findFragmentByTag(NAVIGATOR_TAG) as? EpubNavigatorFragment
        navigator?.let {
            setupNavigatorListener(it)
            navigatorFlow.value = it
        }
    }

    private fun setupNavigatorListener(nav: EpubNavigatorFragment) {
        // 1) DirectionalNavigationAdapter — registered FIRST so it gets priority.
        //    It handles both swipe gestures and edge taps out of the box:
        //      • Swipe left / right edge tap  → goForward()  (next page or chapter)
        //      • Swipe right / left edge tap  → goBackward() (prev page or chapter)
        (nav as? org.readium.r2.navigator.OverflowableNavigator)?.let { overflowableNav ->
            nav.addInputListener(
                org.readium.r2.navigator.util.DirectionalNavigationAdapter(
                    navigator = overflowableNav,
                    animatedTransition = true
                )
            )
        }

        // 2) Tap listener — registered SECOND so edge taps consumed above never reach here.
        //    Only un-consumed taps (centre area) toggle the controls overlay.
        nav.addInputListener(object : InputListener {
            override fun onTap(event: TapEvent): Boolean {
                viewModel.toggleControls()
                return true
            }
        })
    }

    override fun onPause() {
        super.onPause()
        // Save position when leaving
        navigator?.currentLocator?.value?.let { locator ->
            lifecycleScope.launch {
                viewModel.savePosition(locator)
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        viewModel.closeBook()
    }


}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ReaderOverlay(
    viewModel: ReaderViewModel,
    onBack: () -> Unit,
    onNavigateToChapter: (Link) -> Unit,
    onSeekToProgression: (Double) -> Unit
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val isBookmarked by viewModel.isBookmarked.collectAsStateWithLifecycle()
    val settings by viewModel.settingsFlow.collectAsStateWithLifecycle(
        initialValue = com.example.readerapp.data.local.ReaderSettings()
    )

    var isSeeking by remember { mutableStateOf(false) }
    var sliderPosition by remember { mutableFloatStateOf(uiState.progression.toFloat()) }
    var pendingSeek by remember { mutableStateOf<Double?>(null) }

    // Custom seek interaction state.
    var seekBarWidthPx by remember { mutableStateOf(1f) }

    val interactionSource = remember { MutableInteractionSource() }
    val isPressed by interactionSource.collectIsPressedAsState()
    val isDragged by interactionSource.collectIsDraggedAsState()
    val isInteracting = isPressed || isDragged || isSeeking

    LaunchedEffect(uiState.progression) {
        val target = pendingSeek
        if (!isSeeking) {
            if (target == null || abs(uiState.progression - target) < 0.02) {
                pendingSeek = null
                sliderPosition = uiState.progression.toFloat().coerceIn(0f, 1f)
            }
        }
    }

    val readerBgColor = when (settings.readerThemePreset) {
        "Light" -> Color(0xFFFFFFFF)
        "Warm" -> Color(0xFFFAF4E8)
        "Dark" -> Color(0xFF000000)
        else -> if (isSystemInDarkTheme()) Color(0xFF000000) else Color(0xFFFFFFFF)
    }

    // Settings bottom sheet
    val settingsSheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    // TOC bottom sheet  
    val tocSheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)

    Box(modifier = Modifier.fillMaxSize()) {

        // Loading state
        if (uiState.isLoading) {
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.Center
            ) {
                CircularProgressIndicator()
            }
        }

        // Error state
        uiState.error?.let { error ->
            Box(
                modifier = Modifier.fillMaxSize(),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = error,
                    color = MaterialTheme.colorScheme.error,
                    style = MaterialTheme.typography.bodyLarge
                )
            }
        }

        // Animated controls overlay
        AnimatedVisibility(
            visible = uiState.showControls,
            enter = fadeIn(),
            exit = fadeOut()
        ) {
            Box(modifier = Modifier.fillMaxSize()) {
                // Top bar with gradient background (readerBg → transparent, top to bottom)
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.TopCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(readerBgColor, Color.Transparent)
                            )
                        )
                ) {
                    TopAppBar(
                        title = { },
                        navigationIcon = {
                            IconButton(onClick = onBack) {
                                Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                            }
                        },
                        actions = {
                            IconButton(onClick = { /* TODO: Search */ }) {
                                Icon(Icons.Default.Search, contentDescription = "Search")
                            }
                            IconButton(onClick = { viewModel.showToc() }) {
                                Icon(Icons.Filled.List, contentDescription = "Table of Contents")
                            }
                            IconButton(onClick = { viewModel.showSettings() }) {
                                Icon(Icons.Filled.Settings, contentDescription = "Settings")
                            }

                            var showMoreMenu by remember { mutableStateOf(false) }
                            Box {
                                IconButton(onClick = { showMoreMenu = true }) {
                                    Icon(Icons.Default.MoreVert, contentDescription = "More")
                                }
                                DropdownMenu(
                                    expanded = showMoreMenu,
                                    onDismissRequest = { showMoreMenu = false }
                                ) {
                                    DropdownMenuItem(
                                        text = { Text(if (isBookmarked) "Remove Bookmark" else "Add Bookmark") },
                                        onClick = {
                                            viewModel.toggleBookmark()
                                            showMoreMenu = false
                                        },
                                        leadingIcon = {
                                            Icon(
                                                if (isBookmarked) Icons.Filled.Bookmark else Icons.Outlined.BookmarkBorder,
                                                contentDescription = null
                                            )
                                        }
                                    )
                                }
                            }
                        },
                        colors = TopAppBarDefaults.topAppBarColors(
                            containerColor = Color.Transparent,
                            navigationIconContentColor = MaterialTheme.colorScheme.onSurface,
                            actionIconContentColor = MaterialTheme.colorScheme.onSurface
                        )
                    )
                }

                // Bottom bar
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .align(Alignment.BottomCenter)
                        .background(
                            Brush.verticalGradient(
                                colors = listOf(Color.Transparent, readerBgColor),
                                startY = 0f
                            )
                        )
                        .padding(horizontal = 24.dp)
                        .padding(top = 64.dp, bottom = 4.dp)
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        // Progress slider — thin track always visible; show a vertical
                        // seek line only while the user is interacting.
                        val sliderAlpha by animateFloatAsState(
                            targetValue = if (isInteracting) 1f else 0f,
                            label = "sliderInteractAlpha"
                        )
                        val onSurface = MaterialTheme.colorScheme.onSurface
                        val primary = MaterialTheme.colorScheme.primary

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(20.dp)
                                .onSizeChanged { seekBarWidthPx = it.width.toFloat().coerceAtLeast(1f) }
                                .pointerInput(Unit) {
                                    detectDragGestures(
                                        onDragStart = { offset ->
                                            isSeeking = true
                                            val p = (offset.x / seekBarWidthPx).coerceIn(0f, 1f)
                                            sliderPosition = p
                                        },
                                        onDrag = { change, _ ->
                                            change.consume()
                                            val p = (change.position.x / seekBarWidthPx).coerceIn(0f, 1f)
                                            sliderPosition = p
                                        },
                                        onDragEnd = {
                                            isSeeking = false
                                            pendingSeek = sliderPosition.toDouble()
                                            onSeekToProgression(sliderPosition.toDouble())
                                        },
                                        onDragCancel = {
                                            isSeeking = false
                                        }
                                    )
                                }
                                .clickable(
                                    interactionSource = interactionSource,
                                    indication = null
                                ) { /* handled by drag/tap */ },
                            contentAlignment = Alignment.Center
                        ) {
                            // Passive thin track (always visible).
                            Canvas(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(2.dp)
                            ) {
                                val trackY = size.height / 2
                                drawLine(
                                    color = onSurface.copy(alpha = 0.24f),
                                    start = Offset(0f, trackY),
                                    end = Offset(size.width, trackY),
                                    strokeWidth = 2.dp.toPx(),
                                    cap = StrokeCap.Round
                                )
                                drawLine(
                                    color = onSurface.copy(alpha = 0.70f),
                                    start = Offset(0f, trackY),
                                    end = Offset(size.width * sliderPosition, trackY),
                                    strokeWidth = 2.dp.toPx(),
                                    cap = StrokeCap.Round
                                )
                            }

                            // Vertical seek line (only while interacting/seeking).
                            if (isInteracting) {
                                Canvas(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(12.dp)
                                        .graphicsLayer { alpha = sliderAlpha }
                                ) {
                                    val x = size.width * sliderPosition
                                    drawLine(
                                        color = primary,
                                        start = Offset(x, 0f),
                                        end = Offset(x, size.height),
                                        strokeWidth = 2.dp.toPx(),
                                        cap = StrokeCap.Round
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // TOC Bottom Sheet
        if (uiState.showToc) {
            ModalBottomSheet(
                onDismissRequest = { viewModel.hideToc() },
                sheetState = tocSheetState
            ) {
                Text(
                    text = "Table of Contents",
                    style = MaterialTheme.typography.titleLarge,
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)
                )
                HorizontalDivider()
                LazyColumn(
                    modifier = Modifier.fillMaxWidth(),
                    contentPadding = PaddingValues(vertical = 8.dp)
                ) {
                    items(viewModel.tableOfContents) { link ->
                        ListItem(
                            headlineContent = {
                                Text(link.title ?: link.href.toString())
                            },
                            modifier = Modifier.clickable {
                                onNavigateToChapter(link)
                                viewModel.hideToc()
                                viewModel.toggleControls()
                            }
                        )
                    }
                }
            }
        }

        // Settings Bottom Sheet — wrapped in its own theme that honours the UI
        // themeMode/colorPalette setting, independent of the reader theme.
        if (uiState.showSettings) {
            val uiDarkTheme = when (settings.themeMode) {
                "Dark" -> true
                "Light" -> false
                else -> isSystemInDarkTheme()
            }
            ReaderAppTheme(darkTheme = uiDarkTheme, colorPalette = settings.colorPalette) {
                ModalBottomSheet(
                    onDismissRequest = { viewModel.hideSettings() },
                    sheetState = settingsSheetState
                ) {
                    ReaderSettingsContent(
                        settings = settings,
                        onSettingsChange = { newSettings ->
                            viewModel.updateSettings(newSettings)
                        }
                    )
                }
            }
        }
    }
}
